import React from "react";
import { Card, OverlayTrigger, Popover } from "react-bootstrap";

import { BsInfoCircle as InfoIcon } from "react-icons/bs";
// import { FaInfoCircle as InfoIcon } from "react-icons/fa";
import { Divider } from "./divider";
import {
  AMOUNT_DUE,
  BASE_AMOUNT,
  OFFPEAK,
  RETURN_CUSTOMER,
} from "../utils/strings";
import { AnimatedButton } from "./animated-button";

// export export
export function JOB_INVOICE_SLIP({ job }) {
  // format
  const formater = Intl.NumberFormat("en-ZA", {
    style: "currency",
    currency: "zar",
    minimumSignificantDigits: 1,
  });

  //const popover
  const popover = (body) => {
    return (
      <Popover
        id="popover-basic"
        className="rounded-0 border-secondary"
        arrowProps={{ style: { backgroundColor: "red" } }}
      >
        <Popover.Body className="text-secondary fw-bold rounded-0">
          {body}
        </Popover.Body>
      </Popover>
    );
  };

  const InvoiceItem = ({
    leading,
    trailing,
    popOverDesctiption,
    isDiscount = false,
  }) => {
    return (
      <div className="d-flex flex-row justify-content-between align-items-center gap-2">
        <span
          className="text-muted d-flex flex-row justify-content-center align-items-center gap-1"
          style={{ fontWeight: 800 }}
        >
          {leading}{" "}
          <div>
            <AnimatedButton className="px-1">
              <OverlayTrigger
                trigger="click"
                placement="top"
                rootClose={true}
                overlay={popover(`${popOverDesctiption}`)}
              >
                <div>
                  <InfoIcon role="button" color="var(--primary-color)" />
                </div>
              </OverlayTrigger>
            </AnimatedButton>
          </div>
        </span>
        <span
          className="fw-normal"
          style={{ color: `${isDiscount ? "red" : "black"}` }}
        >
          {trailing}
        </span>
      </div>
    );
  };
  //
  const AmountDue = ({ leading, trailing, popOverDesctiption }) => {
    return (
      <div className="d-flex flex-row justify-content-between align-items-center gap-2">
        <span
          style={{ fontWeight: "900" }}
          className="text-secondary d-flex flex-row justify-content-center align-items-center gap-1"
        >
          {leading}{" "}
          <div>
            <AnimatedButton className="px-1">
              <OverlayTrigger
                trigger="click"
                placement="top"
                rootClose={true}
                overlay={popover(`${popOverDesctiption}`)}
              >
                <div>
                  <InfoIcon role="button" color="var(--primary-color)" />
                </div>
              </OverlayTrigger>
            </AnimatedButton>
          </div>
        </span>
        <div>
          <span
            style={{
              fontWeight: "900",
              fontSize: `${18 / 16}rem`,
              color: "black",
            }}
          >
            {trailing}
          </span>
        </div>
      </div>
    );
  };
  //
  return (
    <Card
      className="rounded-0 border-light"
      style={{
        boxShadow: "0 0 5px 0 rgba(0, 0, 0, 0.15)",
        WebkitBoxShadow: "0 0 5px 0 rgba(0, 0, 0, 0.15)",
      }}
    >
      <Card.Body>
        {/*Base amount*/}
        <InvoiceItem
          leading={"Base fee"}
          trailing={`${formater.format(job.base_fee)}`}
          popOverDesctiption={`${BASE_AMOUNT}`}
          isDiscount={false}
        />
        {/*Base amount*/}

        {/*Off peak*/}
        <InvoiceItem
          leading={"Off peak"}
          trailing={`${job.mid_discount > 0 ? "-" : ""} ${formater.format(
            job.mid_discount
          )}`}
          popOverDesctiption={`${OFFPEAK}`}
          isDiscount={true}
        />
        {/*Off peak*/}

        {/*Return Customer*/}
        <InvoiceItem
          leading={"Return customer"}
          trailing={`${
            job.return_customer_discount > 0 ? "-" : ""
          } ${formater.format(job.return_customer_discount)}`}
          popOverDesctiption={`${RETURN_CUSTOMER}`}
          isDiscount={true}
        />
        {/*Return Customer*/}
        <Divider key={"divider"} />
        {/*amount due*/}
        <AmountDue
          leading={"Amount due"}
          trailing={`${formater.format(job.amount_due).replace("ZA", "")}`}
          popOverDesctiption={`${AMOUNT_DUE}`}
        />
        {/*amount due*/}
        <Divider key={"secondary_divider"} />
        {/*two horizontal lines */}
      </Card.Body>
    </Card>
  );
}
