import React from "react";
import { Button, ButtonGroup, Card } from "react-bootstrap";
import { NOTIFICATIONS } from "../utils/notifications";
import { JOB_INVOICE_SLIP } from "../sub-components/quote-invoice-slip";

import {
  NOTIFICATION_TYPE,
  ROUTE_LINKS,
  SHUTTLE_SERVICE,
} from "../utils/strings";

import { IS_LOGGED_IN } from "../utils/loggedin";
import { useNavigate } from "react-router";
import api from "../utils/api";
import { ErrorHandling } from "../utils/error-handling";
import { AwaitCallBack } from "../utils/await-callback";

export function Job({ job }) {
  // React useStates
  const [notificationType, setNotificationType] = new React.useState(
    NOTIFICATION_TYPE.none
  );
  const [leadingText, setLeadingText] = new React.useState("");
  const [trailingText, setTrailingText] = new React.useState("");
  const [disableUI, setDisableUI] = React.useState(false);

  // formaters
  const dateFormater = Intl.DateTimeFormat("en-ZA", {
    weekdays: "long",
    year: "numeric",
    month: "long",
    day: "numeric",
  });

  // time formater
  const timeFormater = Intl.DateTimeFormat("en-Za", {
    hour: "numeric",
    minute: "numeric",
    // second: "numeric",
    timeZone: "Africa/Harare",
    timeZoneName: "short",
  });

  // navigate
  const navigate = useNavigate();
  // notification function
  const setNotification = (type, leading, trailing) => {
    setNotificationType((_) => type);
    setLeadingText((_) => leading);
    setTrailingText((_) => trailing);

    // disable
    const disable = type === NOTIFICATION_TYPE.loading;
    setDisableUI((_) => disable);
  };

  // const
  const cancelJob = async () => {
    // check if logged in
    const [verify, _] = IS_LOGGED_IN();
    //verify
    if (verify) {
      //return
      setNotification(NOTIFICATION_TYPE.loading, "Cancelling Job...", "");

      // const url
      const url = `jobs/api/job/update/${job.id}/`;
      await api
        .patch(url, { job_canceled: true })
        .then(async (r) => {
          //return
          if (r.status === 200) {
            setNotification(
              NOTIFICATION_TYPE.success,
              "Success.",
              "job canceled"
            );

            // await
            await AwaitCallBack(
              () => (window.location.href = ROUTE_LINKS.jobs),
              2000
            );
          }
        })
        .catch((e) => {
          ErrorHandling(e, setNotification);
        });
      return;
    }
    const message =
      "To cancel a job you must be signed in. we'll navigate you to the sign-in page.";
    setNotification(NOTIFICATION_TYPE.info, "Dear valued customer. ", message);
    await AwaitCallBack(() => navigate(ROUTE_LINKS.signin), 6000);
  };

  // function items
  const item = (leading, trailing, makeBold = false) => {
    //
    return (
      <div className="d-flex flex-row justify-content-between align-items-center">
        <span className="text-muted" style={{ fontWeight: 800 }}>
          {/* <Icon icon={DateIcon} dimension={20 / 16} /> */}
          {leading}
        </span>
        <span style={{ fontWeight: makeBold ? "900" : "400" }}>{trailing}</span>
      </div>
    );
  };
  // function items
  const driverNoteItem = (leading, trailing) => {
    //
    return (
      <div className="d-flex flex-column justify-content-start align-items-start">
        <span className="text-muted" style={{ fontWeight: 800 }}>
          {leading}
        </span>
        <span className="fw-normal text-dark">{trailing}</span>
      </div>
    );
  };

  // pick job text
  const setJobHeaderText = (job) => {
    if (job.job_completed) return "COMPLETED";
    else if (job.job_canceled) return "CANCELLED";
    else return "ACTIVE";
  };
  // pick job color
  const setJobHeaderColor = (job) => {
    if (job.job_completed) return "secondary";
    else if (job.job_canceled) return "danger";
    else return "success";
  };

  //
  return (
    <Card
      id={`Invoice-${job.id}`}
      className="card__section mb-3 border-0 rounded-0"
      style={{
        boxShadow: "0 0 5px 0 rgba(0, 0, 0, 0.15)",
        WebkitBoxShadow: "0 0 5px 0 rgba(0, 0, 0, 0.15)",
      }}
    >
      <Card.Header
        className={`fw-bold border-0 rounded-0 bg-${setJobHeaderColor(
          job
        )} text-white`}
      >
        <div className="d-flex flex-row justify-content-between align-items-center">
          <span style={{ fontWeight: 900 }}>INVOICE {job.id}</span>
          <span className="text-white fw-bold">{setJobHeaderText(job)}</span>
        </div>
      </Card.Header>
      <Card.Body>
        {/*NOTIFICATION*/}
        {NOTIFICATIONS(notificationType, leadingText, trailingText)}
        {/*NOTIFICATION*/}
        {/*items*/}
        <div className="mb-3 d-flex flex-column">
          <Card className="rounded-0 border-0">
            <Card.Body className="px-0 pt-0">
              {item("Date", dateFormater.format(new Date(`${job.job_date}`)))}
              {item(
                "Time",
                timeFormater.format(new Date(`${job.job_date} ${job.job_time}`))
              )}

              {item("Helpers", `${job.helpers}`)}
              {item("Floors", `${job.floors}`)}
              {item("Distance", `${job.distance} km`)}
              {item("Vehicle size", `${job.vehicle_size} Ton`)}
              {/* {item("Shuttle", `${SHUTTLE_SERVICE[job.shuttle].description}`)} */}
              {item(
                "Payment method",
                `${
                  `${job.payment_option}`.toUpperCase().charAt(0) +
                  `${job.payment_option}`.slice(1).toLowerCase()
                }`,
                false
              )}
              {driverNoteItem("Driver note", `${job.driver_note}`)}

              {/* {item("Referal code", `${job.referal_code}`)} */}
            </Card.Body>
          </Card>

          <div className="my-2">
            <JOB_INVOICE_SLIP job={job} />
          </div>
        </div>
        {/*items*/}
        <Card.Footer className="p-0 border-0 bg-transparent d-flex flex-row justify-content-end align-items-center">
          <ButtonGroup>
            <Button
              // reloadDocument={true}
              // to={`/jobs/job/${job.id}/update`}
              disabled={job.job_canceled || disableUI || job.job_completed}
              variant="outline-primary"
              className="rounded-0 border-0 fw-bold"
              onClick={() => {
                let anchor = window.document.createElement("a");
                anchor.href = `/jobs/job/${job.id}/update`;
                anchor.target = "_blank";
                anchor.click();
              }}
            >
              Update
            </Button>
            <Button
              variant="outline-danger"
              disabled={job.job_canceled || disableUI || job.job_completed}
              className="border-0 rounded-0 fw-bold"
              onClick={async () => {
                const title = document.getElementById("JOBS_TITLE");
                const jobRef = document.getElementById(`Invoice-${job.id}`);
                window.scrollTo(0, jobRef.offsetTop - title.offsetTop);
                // run
                await AwaitCallBack(async () => await cancelJob());
              }}
            >
              Cancel
            </Button>
          </ButtonGroup>
        </Card.Footer>
      </Card.Body>
    </Card>
  );
}
